/* ============================================================
   LIQUID GLASS DESIGN SYSTEM — STIK ERP
   iOS-inspired glassmorphism with animations
   ============================================================ */

*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

:root {
    /* Colors */
    --bg-base: #0a0a0f;
    --bg-secondary: #0f0f1a;
    --bg-tertiary: #13131f;

    --glass-1: rgba(255, 255, 255, 0.04);
    --glass-2: rgba(255, 255, 255, 0.07);
    --glass-3: rgba(255, 255, 255, 0.10);
    --glass-4: rgba(255, 255, 255, 0.14);

    --border-subtle: rgba(255, 255, 255, 0.06);
    --border-default: rgba(255, 255, 255, 0.10);
    --border-strong: rgba(255, 255, 255, 0.18);
    --border-accent: rgba(100, 160, 255, 0.30);

    --text-primary: rgba(255, 255, 255, 0.92);
    --text-secondary: rgba(255, 255, 255, 0.55);
    --text-tertiary: rgba(255, 255, 255, 0.32);

    --accent-blue: #4da6ff;
    --accent-blue-dim: rgba(77, 166, 255, 0.15);
    --accent-green: #34d399;
    --accent-green-dim: rgba(52, 211, 153, 0.15);
    --accent-amber: #fbbf24;
    --accent-amber-dim: rgba(251, 191, 36, 0.15);
    --accent-red: #ff6b6b;
    --accent-red-dim: rgba(255, 107, 107, 0.15);

    --status-planned: #7c8ff5;
    --status-planned-bg: rgba(124, 143, 245, 0.12);
    --status-active: #34d399;
    --status-active-bg: rgba(52, 211, 153, 0.12);
    --status-done: rgba(255,255,255,0.4);
    --status-done-bg: rgba(255,255,255,0.07);

    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 20px;
    --space-6: 24px;
    --space-8: 32px;
    --space-16: 64px;

    --radius-sm: 8px;
    --radius-md: 12px;
    --radius-lg: 16px;
    --radius-xl: 20px;
    --radius-2xl: 24px;
    --radius-full: 9999px;

    --shadow-sm: 0 1px 3px rgba(0,0,0,0.4);
    --shadow-md: 0 4px 16px rgba(0,0,0,0.5);
    --shadow-lg: 0 8px 32px rgba(0,0,0,0.6);

    --transition-fast: 120ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 350ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-spring: 400ms cubic-bezier(0.34, 1.56, 0.64, 1);

    --font-sans: 'DM Sans', -apple-system, BlinkMacSystemFont, sans-serif;
    --font-mono: 'DM Mono', monospace;
}

/* ============================================================
   ANIMATIONS — LIQUID GLASS EFFECTS
   ============================================================ */

@keyframes slideInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes slideInDown {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes slideInLeft {
    from {
        opacity: 0;
        transform: translateX(-20px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

@keyframes fadeInScale {
    from {
        opacity: 0;
        transform: scale(0.95);
    }
    to {
        opacity: 1;
        transform: scale(1);
    }
}

@keyframes glassShimmer {
    0%, 100% {
        box-shadow: 0 0 20px rgba(77, 166, 255, 0.1),
                    inset 0 0 20px rgba(255,255,255,0.05);
    }
    50% {
        box-shadow: 0 0 40px rgba(77, 166, 255, 0.2),
                    inset 0 0 30px rgba(255,255,255,0.1);
    }
}

@keyframes liquidFloat {
    0%, 100% {
        transform: translateY(0px) rotate(0deg);
    }
    50% {
        transform: translateY(-8px) rotate(1deg);
    }
}

@keyframes pulseGlow {
    0%, 100% {
        box-shadow: 0 0 20px rgba(77, 166, 255, 0.1);
    }
    50% {
        box-shadow: 0 0 40px rgba(77, 166, 255, 0.25);
    }
}

@keyframes shimmerMove {
    0% {
        background-position: -1000px 0;
    }
    100% {
        background-position: 1000px 0;
    }
}

/* ============================================================
   GLOBAL STYLES
   ============================================================ */

html, body {
    width: 100%;
    height: 100%;
    background: var(--bg-base);
    color: var(--text-primary);
    font-family: var(--font-sans);
    font-size: 14px;
    line-height: 1.6;
    overflow: hidden;
}

body {
    background: linear-gradient(135deg, var(--bg-base) 0%, var(--bg-secondary) 100%);
}

#root {
    width: 100%;
    height: 100%;
    display: flex;
}

a {
    color: var(--accent-blue);
    text-decoration: none;
    transition: color var(--transition-base);
}

a:hover {
    color: #6ab9ff;
}

/* ============================================================
   LIQUID GLASS CONTAINERS
   ============================================================ */

.glass-card {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.12) 0%,
        rgba(255, 255, 255, 0.04) 100%);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border: 1px solid rgba(255, 255, 255, 0.15);
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-md),
                inset 0 1px 0 rgba(255, 255, 255, 0.15),
                0 0 30px rgba(77, 166, 255, 0.08);
    padding: var(--space-6);
    transition: all var(--transition-base);
    animation: fadeInScale 0.5s ease-out;
}

.glass-card:hover {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.15) 0%,
        rgba(255, 255, 255, 0.06) 100%);
    box-shadow: var(--shadow-lg),
                inset 0 1px 0 rgba(255, 255, 255, 0.18),
                0 0 50px rgba(77, 166, 255, 0.15);
    border-color: rgba(77, 166, 255, 0.3);
    transform: translateY(-4px);
}

.glass-container {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.08) 0%,
        rgba(255, 255, 255, 0.02) 100%);
    backdrop-filter: blur(40px) saturate(200%);
    -webkit-backdrop-filter: blur(40px) saturate(200%);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius-2xl);
    position: relative;
    overflow: hidden;
    animation: slideInUp 0.6s ease-out;
}

.glass-container::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(77, 166, 255, 0.1) 0%, transparent 70%);
    pointer-events: none;
    animation: liquidFloat 6s ease-in-out infinite;
}

/* ============================================================
   BUTTONS — GLASS EFFECT
   ============================================================ */

.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--space-2);
    padding: var(--space-3) var(--space-4);
    font-size: 14px;
    font-weight: 500;
    border: none;
    border-radius: var(--radius-lg);
    cursor: pointer;
    transition: all var(--transition-base);
    position: relative;
    overflow: hidden;
    backdrop-filter: blur(10px);
    font-family: inherit;
}

.btn::before {
    content: '';
    position: absolute;
    inset: 0;
    background: radial-gradient(circle at 50% 50%, rgba(255,255,255,0.3), transparent);
    opacity: 0;
    transition: opacity var(--transition-base);
    pointer-events: none;
    border-radius: inherit;
}

.btn:hover::before {
    opacity: 1;
}

.btn-primary {
    background: linear-gradient(135deg, #4da6ff 0%, #3e7eff 100%);
    color: #fff;
    box-shadow: 0 4px 15px rgba(77, 166, 255, 0.3),
                inset 0 1px 0 rgba(255, 255, 255, 0.3);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(77, 166, 255, 0.5),
                inset 0 1px 0 rgba(255, 255, 255, 0.4);
}

.btn-primary:active {
    transform: translateY(0);
    box-shadow: 0 2px 10px rgba(77, 166, 255, 0.3);
}

.btn-ghost {
    background: rgba(255, 255, 255, 0.08);
    color: var(--text-primary);
    border: 1px solid rgba(255, 255, 255, 0.1);
}

.btn-ghost:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.15);
    box-shadow: 0 0 20px rgba(255, 255, 255, 0.08);
}

.btn-icon {
    width: 36px;
    height: 36px;
    padding: 0;
    background: rgba(255, 255, 255, 0.06);
    color: var(--text-secondary);
    border: 1px solid rgba(255, 255, 255, 0.08);
}

.btn-icon:hover {
    background: rgba(255, 255, 255, 0.10);
    color: var(--text-primary);
    box-shadow: 0 0 15px rgba(77, 166, 255, 0.1);
}

.btn-sm {
    padding: var(--space-2) var(--space-3);
    font-size: 13px;
}

/* ============================================================
   MODALS & OVERLAYS
   ============================================================ */

.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(5px);
    -webkit-backdrop-filter: blur(5px);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    animation: fadeInScale 0.3s ease-out;
}

.modal {
    background: linear-gradient(135deg,
        rgba(15, 15, 26, 0.95) 0%,
        rgba(19, 19, 31, 0.95) 100%);
    backdrop-filter: blur(30px) saturate(180%);
    -webkit-backdrop-filter: blur(30px) saturate(180%);
    border: 1px solid rgba(255, 255, 255, 0.15);
    border-radius: var(--radius-2xl);
    box-shadow: var(--shadow-lg),
                0 0 60px rgba(77, 166, 255, 0.1),
                inset 0 1px 0 rgba(255, 255, 255, 0.2);
    width: 90%;
    max-width: 500px;
    max-height: 85vh;
    overflow-y: auto;
    animation: slideInDown 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.modal-header {
    padding: var(--space-6);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-4);
}

.modal-title {
    font-size: 18px;
    font-weight: 600;
    color: var(--text-primary);
}

.modal-body {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-4);
}

.modal-footer {
    padding: var(--space-6);
    border-top: 1px solid rgba(255, 255, 255, 0.08);
    display: flex;
    gap: var(--space-3);
    justify-content: flex-end;
}

/* ============================================================
   FORMS & INPUTS
   ============================================================ */

.input, textarea, select {
    width: 100%;
    padding: var(--space-3) var(--space-4);
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255, 255, 255, 0.10);
    border-radius: var(--radius-md);
    color: var(--text-primary);
    font-family: inherit;
    font-size: 14px;
    transition: all var(--transition-base);
    backdrop-filter: blur(10px);
}

.input::placeholder {
    color: var(--text-tertiary);
}

.input:hover, textarea:hover, select:hover {
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(255, 255, 255, 0.15);
    box-shadow: 0 0 15px rgba(77, 166, 255, 0.05);
}

.input:focus, textarea:focus, select:focus {
    outline: none;
    background: rgba(255, 255, 255, 0.10);
    border-color: rgba(77, 166, 255, 0.5);
    box-shadow: 0 0 0 3px rgba(77, 166, 255, 0.1),
                0 0 20px rgba(77, 166, 255, 0.2);
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
    animation: slideInUp 0.4s ease-out;
}

.form-label {
    font-size: 13px;
    font-weight: 500;
    color: var(--text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.form-error {
    font-size: 12px;
    color: var(--accent-red);
    margin-top: -4px;
}

/* ============================================================
   TABLES
   ============================================================ */

table {
    width: 100%;
    border-collapse: collapse;
    animation: slideInUp 0.5s ease-out;
}

thead {
    background: rgba(77, 166, 255, 0.08);
    border-bottom: 1px solid rgba(255, 255, 255, 0.10);
}

th {
    padding: var(--space-4);
    text-align: left;
    font-size: 12px;
    font-weight: 600;
    color: var(--text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

td {
    padding: var(--space-4);
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    color: var(--text-primary);
    font-size: 14px;
}

tbody tr {
    transition: all var(--transition-base);
}

tbody tr:hover {
    background: rgba(77, 166, 255, 0.08);
    box-shadow: inset 0 0 15px rgba(77, 166, 255, 0.05);
}

/* ============================================================
   BADGES & STATUS
   ============================================================ */

.badge {
    display: inline-flex;
    align-items: center;
    gap: var(--space-1);
    padding: var(--space-1) var(--space-3);
    font-size: 12px;
    font-weight: 500;
    border-radius: var(--radius-full);
    backdrop-filter: blur(10px);
    transition: all var(--transition-base);
}

.badge-planned {
    background: var(--status-planned-bg);
    color: var(--status-planned);
    border: 1px solid rgba(124, 143, 245, 0.3);
}

.badge-active {
    background: var(--status-active-bg);
    color: var(--status-active);
    border: 1px solid rgba(52, 211, 153, 0.3);
    box-shadow: 0 0 10px rgba(52, 211, 153, 0.15);
}

.badge-completed {
    background: var(--status-done-bg);
    color: var(--text-secondary);
    border: 1px solid rgba(255, 255, 255, 0.15);
}

/* ============================================================
   TOAST NOTIFICATIONS — GLASS EFFECT
   ============================================================ */

.toast-container {
    position: fixed;
    bottom: var(--space-6);
    right: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-3);
    z-index: 2000;
    pointer-events: none;
}

.toast {
    display: flex;
    align-items: center;
    gap: var(--space-3);
    padding: var(--space-4) var(--space-5);
    background: linear-gradient(135deg,
        rgba(15, 15, 26, 0.95) 0%,
        rgba(19, 19, 31, 0.95) 100%);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid rgba(255, 255, 255, 0.15);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-md),
                0 0 30px rgba(77, 166, 255, 0.1);
    font-size: 14px;
    color: var(--text-primary);
    pointer-events: auto;
    animation: slideInUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.toast-success {
    border-color: rgba(52, 211, 153, 0.3);
    box-shadow: var(--shadow-md), 0 0 30px rgba(52, 211, 153, 0.15);
}

.toast-error {
    border-color: rgba(255, 107, 107, 0.3);
    box-shadow: var(--shadow-md), 0 0 30px rgba(255, 107, 107, 0.15);
}

.toast-warning {
    border-color: rgba(251, 191, 36, 0.3);
    box-shadow: var(--shadow-md), 0 0 30px rgba(251, 191, 36, 0.15);
}

/* ============================================================
   PAGE & LAYOUT
   ============================================================ */

.page-enter {
    animation: slideInUp 0.5s ease-out;
}

.empty-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: var(--space-16);
    text-align: center;
}

.empty-state-title {
    font-size: 16px;
    font-weight: 600;
    color: var(--text-secondary);
}

/* ============================================================
   UTILITY CLASSES
   ============================================================ */

.grid-2 {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-4);
}

.grid-4 {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--space-5);
    width: 100%;
}

@media (max-width: 1400px) {
    .grid-4 {
        grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    }
}

@media (max-width: 900px) {
    .grid-4 {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 600px) {
    .grid-4 {
        grid-template-columns: 1fr;
    }
}

/* ============================================================
   STAT CARDS
   ============================================================ */

.stat-card {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.10) 0%,
        rgba(255, 255, 255, 0.03) 100%);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius-xl);
    padding: var(--space-5);
    transition: all var(--transition-base);
    animation: fadeInScale 0.5s ease-out;
    position: relative;
    overflow: hidden;
}

.stat-card::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(77, 166, 255, 0.08) 0%, transparent 70%);
    pointer-events: none;
    transition: all var(--transition-slow);
}

.stat-card:hover {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.14) 0%,
        rgba(255, 255, 255, 0.05) 100%);
    border-color: rgba(77, 166, 255, 0.3);
    box-shadow: 0 0 30px rgba(77, 166, 255, 0.15),
                inset 0 1px 0 rgba(255, 255, 255, 0.15);
    transform: translateY(-6px);
}

.stat-card:hover::before {
    top: -30%;
    right: -30%;
}

.stat-value {
    font-size: 28px;
    font-weight: 700;
    color: var(--text-primary);
    letter-spacing: -0.02em;
    margin-bottom: var(--space-2);
}

.stat-label {
    font-size: 12px;
    font-weight: 600;
    color: var(--text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* ============================================================
   PROGRESS BAR
   ============================================================ */

.progress-bar {
    width: 100%;
    height: 4px;
    background: rgba(255, 255, 255, 0.08);
    border-radius: 2px;
    overflow: hidden;
    position: relative;
}

.progress-bar-fill {
    height: 100%;
    background: linear-gradient(90deg,
        #4da6ff 0%,
        #34d399 100%);
    border-radius: 2px;
    transition: width var(--transition-base);
    box-shadow: 0 0 10px rgba(77, 166, 255, 0.3);
}

.shimmer {
    animation: glassShimmer 3s ease-in-out infinite;
}

.float {
    animation: liquidFloat 4s ease-in-out infinite;
}

.pulse-glow {
    animation: pulseGlow 2s ease-in-out infinite;
}

/* ============================================================
   SCROLLBAR STYLING
   ============================================================ */

::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: rgba(255, 255, 255, 0.02);
}

::-webkit-scrollbar-thumb {
    background: rgba(77, 166, 255, 0.3);
    border-radius: 4px;
    transition: background var(--transition-base);
}

::-webkit-scrollbar-thumb:hover {
    background: rgba(77, 166, 255, 0.5);
}

{
  "name": "erp-learning-frontend",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1",
    "react-router-dom": "^6.26.0",
    "zustand": "^5.0.0",
    "date-fns": "^3.6.0",
    "lucide-react": "^0.436.0"
  },
  "devDependencies": {
    "@types/react": "^18.3.3",
    "@types/react-dom": "^18.3.0",
    "@vitejs/plugin-react": "^4.3.1",
    "vite": "^5.4.0"
  }
}

import React from 'react'
import { Outlet } from 'react-router-dom'
import Sidebar from './Sidebar.jsx'

export default function Layout() {
    return (
        <div style={{
            display: 'flex',
            height: '100%',
            position: 'relative',
            zIndex: 1,
        }}>
            <Sidebar />
            <main style={{
                flex: 1,
                overflowY: 'auto',
                overflowX: 'hidden',
                padding: '28px 32px',
                position: 'relative',
            }}>
                <Outlet />
            </main>
        </div>
    )
}

import React, { useState, useEffect } from 'react'
import { Outlet } from 'react-router-dom'
import Sidebar from './Sidebar.jsx'

export default function Layout() {
    const [sidebarWidth, setSidebarWidth] = useState(280)

    return (
        <div style={{
            display: 'flex',
            height: '100%',
            position: 'relative',
            zIndex: 1,
        }}>
            <Sidebar onWidthChange={setSidebarWidth} />
            <main style={{
                flex: 1,
                marginLeft: `${sidebarWidth}px`,
                overflowY: 'auto',
                overflowX: 'hidden',
                padding: '28px 32px',
                position: 'relative',
                transition: 'margin-left 0.3s ease',
            }} className="main-content-transition">
                <Outlet />
            </main>
        </div>
    )
}

import React, { useState, useEffect } from 'react'
import { NavLink } from 'react-router-dom'
import {
    LayoutDashboard, BookOpen, Users, Settings,
    GraduationCap, Building2, ChevronLeft, ChevronRight
} from 'lucide-react'

const navigation = [
    { name: 'Дашборд', href: '/', icon: LayoutDashboard },
    { name: 'Курсы', href: '/courses', icon: BookOpen },
    { name: 'Группы', href: '/groups', icon: GraduationCap },
    { name: 'Сотрудники', href: '/employees', icon: Users },
    { name: 'Компании', href: '/companies', icon: Building2 },
    { name: 'Настройки', href: '/settings', icon: Settings },
]

export default function Sidebar({ onWidthChange }) {
    const [isCollapsed, setIsCollapsed] = useState(false)

    useEffect(() => {
        onWidthChange?.(isCollapsed ? 72 : 280)
    }, [isCollapsed, onWidthChange])

    const handleToggle = () => {
        setIsCollapsed(!isCollapsed)
    }

    return (
        <aside style={{
            width: isCollapsed ? '72px' : '280px',
            background: 'linear-gradient(135deg, rgba(255, 255, 255, 0.05) 0%, rgba(255, 255, 255, 0.02) 100%)',
            backdropFilter: 'blur(20px)',
            borderRight: '1px solid rgba(255, 255, 255, 0.08)',
            padding: '24px 0',
            position: 'fixed',
            height: '100vh',
            left: 0,
            top: 0,
            zIndex: 10,
            transition: 'width 0.3s ease',
            overflow: 'hidden',
        }} className="sidebar-transition">
            {/* Logo */}
            <div style={{
                padding: '0 24px 32px',
                borderBottom: '1px solid rgba(255, 255, 255, 0.08)',
                marginBottom: '24px',
                position: 'relative',
            }}>
                <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '12px',
                    opacity: isCollapsed ? 0 : 1,
                    transition: 'opacity 0.3s ease',
                }}>
                    <div style={{
                        width: '32px',
                        height: '32px',
                        background: 'linear-gradient(135deg, #4da6ff 0%, #34d399 100%)',
                        borderRadius: '8px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '16px',
                        fontWeight: '700',
                        color: 'white',
                        flexShrink: 0,
                    }}>
                        S
                    </div>
                    <div style={{
                        overflow: 'hidden',
                        whiteSpace: 'nowrap',
                    }}>
                        <div style={{
                            fontSize: '16px',
                            fontWeight: '700',
                            color: 'white',
                            letterSpacing: '-0.02em',
                        }}>
                            STIK ERP
                        </div>
                        <div style={{
                            fontSize: '11px',
                            color: 'rgba(255, 255, 255, 0.6)',
                            marginTop: '2px',
                        }}>
                            Корпоративное обучение
                        </div>
                    </div>
                </div>

                {/* Collapse Button */}
                <button
                    onClick={handleToggle}
                    style={{
                        position: 'absolute',
                        right: '12px',
                        top: '50%',
                        transform: 'translateY(-50%)',
                        width: '32px',
                        height: '32px',
                        background: 'rgba(255, 255, 255, 0.1)',
                        border: '1px solid rgba(255, 255, 255, 0.2)',
                        borderRadius: '8px',
                        color: 'white',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        transition: 'all 0.2s ease',
                        zIndex: 20,
                    }}
                    onMouseEnter={(e) => {
                        e.currentTarget.style.background = 'rgba(255, 255, 255, 0.2)'
                        e.currentTarget.style.borderColor = 'rgba(77, 166, 255, 0.4)'
                    }}
                    onMouseLeave={(e) => {
                        e.currentTarget.style.background = 'rgba(255, 255, 255, 0.1)'
                        e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.2)'
                    }}
                >
                    {isCollapsed ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
                </button>
            </div>

            {/* Navigation */}
            <nav style={{ padding: '0 16px' }}>
                <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                    {navigation.map((item) => (
                        <li key={item.name} style={{ marginBottom: '4px' }}>
                            <NavLink
                                to={item.href}
                                title={isCollapsed ? item.name : ''}
                                style={({ isActive }) => ({
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '12px',
                                    padding: '12px 16px',
                                    borderRadius: '12px',
                                    textDecoration: 'none',
                                    color: isActive ? 'white' : 'rgba(255, 255, 255, 0.7)',
                                    background: isActive ? 'rgba(77, 166, 255, 0.2)' : 'transparent',
                                    border: isActive ? '1px solid rgba(77, 166, 255, 0.3)' : '1px solid transparent',
                                    transition: 'all 0.2s ease',
                                    fontSize: '14px',
                                    fontWeight: '500',
                                    justifyContent: isCollapsed ? 'center' : 'flex-start',
                                    minWidth: isCollapsed ? '40px' : 'auto',
                                })}
                                onMouseEnter={(e) => {
                                    if (!e.currentTarget.classList.contains('active')) {
                                        e.currentTarget.style.background = 'rgba(255, 255, 255, 0.05)'
                                    }
                                }}
                                onMouseLeave={(e) => {
                                    if (!e.currentTarget.classList.contains('active')) {
                                        e.currentTarget.style.background = 'transparent'
                                    }
                                }}
                            >
                                <item.icon size={isCollapsed ? 9 : 18} />
                                {!isCollapsed && (
                                    <span style={{
                                        opacity: isCollapsed ? 0 : 1,
                                        transition: 'opacity 0.3s ease',
                                        whiteSpace: 'nowrap',
                                        overflow: 'hidden',
                                    }}>
                                        {item.name}
                                    </span>
                                )}
                            </NavLink>
                        </li>
                    ))}
                </ul>
            </nav>

            {/* Footer */}
            <div style={{
                position: 'absolute',
                bottom: '24px',
                left: '16px',
                right: '16px',
                opacity: isCollapsed ? 0 : 1,
                transition: 'opacity 0.3s ease',
            }}>
                <div style={{
                    padding: '16px',
                    background: 'rgba(255, 255, 255, 0.05)',
                    borderRadius: '12px',
                    border: '1px solid rgba(255, 255, 255, 0.08)',
                }}>
                    <div style={{
                        fontSize: '12px',
                        color: 'rgba(255, 255, 255, 0.6)',
                        textAlign: 'center',
                        lineHeight: '1.4',
                    }}>
                        STIK ERP v1.0.0
                        <br />
                        2026 © Все права защищены
                    </div>
                </div>
            </div>
        </aside>
    )
}

/* ============================================================
   CSS RESET & BASE STYLES
   ============================================================ */

* {
    box-sizing: border-box;
}

html {
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;
    font-feature-settings: 'cv02', 'cv03', 'cv04', 'cv11';
    font-variation-settings: 'opsz' 32;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
    -webkit-text-size-adjust: 100%;
}

body {
    margin: 0;
    padding: 0;
    background: linear-gradient(135deg,
        #0a0a0f 0%,
        #1a1a2e 50%,
        #16213e 100%);
    background-attachment: fixed;
    color: #ffffff;
    font-size: 14px;
    line-height: 1.5;
    min-height: 100vh;
    overflow-x: hidden;
}

/* ============================================================
   CSS CUSTOM PROPERTIES (VARIABLES)
   ============================================================ */

:root {
    /* Colors */
    --text-primary: #ffffff;
    --text-secondary: #a1a1aa;
    --text-tertiary: #71717a;
    --text-muted: #52525b;

    --bg-primary: #0a0a0f;
    --bg-secondary: #1a1a2e;
    --bg-tertiary: #16213e;

    --border-default: rgba(255, 255, 255, 0.1);
    --border-subtle: rgba(255, 255, 255, 0.05);
    --border-focus: rgba(77, 166, 255, 0.5);

    --accent-blue: #4da6ff;
    --accent-green: #34d399;
    --accent-yellow: #fbbf24;
    --accent-red: #ef4444;
    --accent-purple: #a855f7;

    --status-active: #34d399;
    --status-planned: #fbbf24;
    --status-done: #71717a;

    /* Glassmorphism */
    --glass-1: rgba(255, 255, 255, 0.05);
    --glass-2: rgba(255, 255, 255, 0.08);
    --glass-3: rgba(255, 255, 255, 0.12);

    /* Spacing */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 20px;
    --space-6: 24px;
    --space-8: 32px;
    --space-16: 64px;

    /* Border radius */
    --radius-sm: 8px;
    --radius-md: 12px;
    --radius-lg: 16px;
    --radius-xl: 20px;
    --radius-2xl: 24px;
    --radius-full: 9999px;

    /* Shadows */
    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
    --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
    --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);

    /* Transitions */
    --transition-fast: 0.15s ease;
    --transition-base: 0.2s ease;
    --transition-slow: 0.3s ease;
}

/* ============================================================
   UTILITY CLASSES
   ============================================================ */

.grid-2 {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: var(--space-4);
}

.grid-4 {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--space-5);
    width: 100%;
}

@media (max-width: 1400px) {
    .grid-4 {
        grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    }
}

@media (max-width: 900px) {
    .grid-4 {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 600px) {
    .grid-4 {
        grid-template-columns: 1fr;
    }
}

/* ============================================================
   GLASSMORPHISM COMPONENTS
   ============================================================ */

.glass-card {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.10) 0%,
        rgba(255, 255, 255, 0.03) 100%);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius-xl);
}

/* ============================================================
   STAT CARDS
   ============================================================ */

.stat-card {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.10) 0%,
        rgba(255, 255, 255, 0.03) 100%);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius-xl);
    padding: var(--space-5);
    transition: all var(--transition-base);
    animation: fadeInScale 0.5s ease-out;
    position: relative;
    overflow: hidden;
}

.stat-card::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(77, 166, 255, 0.08) 0%, transparent 70%);
    pointer-events: none;
    transition: all var(--transition-slow);
}

.stat-card:hover {
    background: linear-gradient(135deg,
        rgba(255, 255, 255, 0.14) 0%,
        rgba(255, 255, 255, 0.05) 100%);
    border-color: rgba(77, 166, 255, 0.3);
    box-shadow: 0 0 30px rgba(77, 166, 255, 0.15),
                inset 0 1px 0 rgba(255, 255, 255, 0.15);
    transform: translateY(-6px);
}

.stat-card:hover::before {
    top: -30%;
    right: -30%;
}

.stat-value {
    font-size: 28px;
    font-weight: 700;
    color: var(--text-primary);
    letter-spacing: -0.02em;
    margin-bottom: var(--space-2);
}

.stat-label {
    font-size: 12px;
    font-weight: 600;
    color: var(--text-secondary);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* ============================================================
   PROGRESS BAR
   ============================================================ */

.progress-bar {
    width: 100%;
    height: 4px;
    background: rgba(255, 255, 255, 0.08);
    border-radius: 2px;
    overflow: hidden;
    position: relative;
}

.progress-bar-fill {
    height: 100%;
    background: linear-gradient(90deg,
        #4da6ff 0%,
        #34d399 100%);
    border-radius: 2px;
    transition: width var(--transition-base);
    box-shadow: 0 0 10px rgba(77, 166, 255, 0.3);
}

/* ============================================================
   BUTTONS
   ============================================================ */

.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--space-2);
    padding: var(--space-3) var(--space-4);
    border-radius: var(--radius-md);
    font-size: 14px;
    font-weight: 500;
    text-decoration: none;
    border: none;
    cursor: pointer;
    transition: all var(--transition-fast);
    white-space: nowrap;
}

.btn-primary {
    background: var(--accent-blue);
    color: white;
}

.btn-primary:hover {
    background: #3b82f6;
    box-shadow: 0 0 20px rgba(77, 166, 255, 0.4);
}

.btn-secondary {
    background: var(--glass-2);
    color: var(--text-primary);
    border: 1px solid var(--border-default);
}

.btn-secondary:hover {
    background: var(--glass-3);
    border-color: var(--border-focus);
}

.btn-ghost {
    background: transparent;
    color: var(--text-secondary);
    border: 1px solid transparent;
}

.btn-ghost:hover {
    background: var(--glass-1);
    color: var(--text-primary);
}

.btn-sm {
    padding: var(--space-2) var(--space-3);
    font-size: 12px;
}

.btn-lg {
    padding: var(--space-4) var(--space-6);
    font-size: 16px;
}

/* ============================================================
   FORM ELEMENTS
   ============================================================ */

.input {
    width: 100%;
    padding: var(--space-3) var(--space-4);
    background: var(--glass-2);
    border: 1px solid var(--border-default);
    border-radius: var(--radius-md);
    color: var(--text-primary);
    font-size: 14px;
    transition: all var(--transition-fast);
}

.input:focus {
    outline: none;
    border-color: var(--border-focus);
    box-shadow: 0 0 0 3px rgba(77, 166, 255, 0.1);
}

.input::placeholder {
    color: var(--text-tertiary);
}

.select {
    appearance: none;
    background: var(--glass-2);
    border: 1px solid var(--border-default);
    border-radius: var(--radius-md);
    padding: var(--space-3) var(--space-4);
    color: var(--text-primary);
    font-size: 14px;
    cursor: pointer;
    transition: all var(--transition-fast);
}

.select:focus {
    outline: none;
    border-color: var(--border-focus);
    box-shadow: 0 0 0 3px rgba(77, 166, 255, 0.1);
}

/* ============================================================
   TABLES
   ============================================================ */

table {
    width: 100%;
    border-collapse: collapse;
    border-radius: var(--radius-lg);
    overflow: hidden;
}

thead {
    background: var(--glass-1);
}

th, td {
    padding: var(--space-4);
    text-align: left;
    border-bottom: 1px solid var(--border-subtle);
}

th {
    font-weight: 600;
    color: var(--text-secondary);
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

td {
    color: var(--text-primary);
    font-size: 13px;
}

/* ============================================================
   EMPTY STATES
   ============================================================ */

.empty-state {
    text-align: center;
    padding: var(--space-8);
}

.empty-state-title {
    font-size: 16px;
    font-weight: 600;
    color: var(--text-secondary);
    margin-bottom: var(--space-2);
}

.empty-state-description {
    font-size: 14px;
    color: var(--text-tertiary);
}

/* ============================================================
   ANIMATIONS
   ============================================================ */

@keyframes fadeInScale {
    from {
        opacity: 0;
        transform: scale(0.95);
    }
    to {
        opacity: 1;
        transform: scale(1);
    }
}

@keyframes slideInFromBottom {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.page-enter {
    animation: slideInFromBottom 0.4s ease-out;
}

/* ============================================================
   RESPONSIVE DESIGN
   ============================================================ */

@media (max-width: 768px) {
    body {
        font-size: 13px;
    }

    main {
        padding: var(--space-4) !important;
    }

    .grid-4 {
        grid-template-columns: 1fr;
        gap: var(--space-4);
    }

    .stat-card {
        padding: var(--space-4);
    }

    .stat-value {
        font-size: 24px;
    }
}

@media (max-width: 480px) {
    .btn {
        width: 100%;
    }

    table {
        font-size: 12px;
    }

    th, td {
        padding: var(--space-3);
    }
}

/* ============================================================
   UTILITIES
   ============================================================ */

.text-center { text-align: center; }
.text-left { text-align: left; }
.text-right { text-align: right; }

.mb-1 { margin-bottom: var(--space-1); }
.mb-2 { margin-bottom: var(--space-2); }
.mb-3 { margin-bottom: var(--space-3); }
.mb-4 { margin-bottom: var(--space-4); }
.mb-5 { margin-bottom: var(--space-5); }
.mb-6 { margin-bottom: var(--space-6); }

.mt-1 { margin-top: var(--space-1); }
.mt-2 { margin-top: var(--space-2); }
.mt-3 { margin-top: var(--space-3); }
.mt-4 { margin-top: var(--space-4); }
.mt-5 { margin-top: var(--space-5); }
.mt-6 { margin-top: var(--space-6); }

.hidden { display: none; }
.flex { display: flex; }
.block { display: block; }
.inline-block { display: inline-block; }

.items-center { align-items: center; }
.justify-center { justify-content: center; }
.justify-between { justify-content: space-between; }
.justify-around { justify-content: space-around; }

.w-full { width: 100%; }
.h-full { height: 100%; }

.cursor-pointer { cursor: pointer; }
.cursor-default { cursor: default; }

/* ============================================================
   LAYOUT & SIDEBAR
   ============================================================ */

.sidebar-transition {
    transition: width 0.3s ease;
}

.main-content-transition {
    transition: margin-left 0.3s ease;
}

import React from 'react'
import { useNavigate } from 'react-router-dom'
import {
    GraduationCap, BookOpen, Users, FileText,
    AlertTriangle, ChevronRight, Calendar, AlertCircle
} from 'lucide-react'
import { useStore, calcGroupProgress, calcSpecTotals } from '../store/useStore.js'
import StatusBadge from '../components/ui/StatusBadge.jsx'
import PageHeader from '../components/ui/PageHeader.jsx'

const fmt = (n) => new Intl.NumberFormat('ru-RU').format(Math.round(n))

export default function Dashboard() {
    const navigate = useNavigate()
    const { groups, courses, employees, companies, specifications } = useStore()

    const activeGroups = groups.filter(g => g.status === 'active')
    const plannedGroups = groups.filter(g => g.status === 'planned')
    const totalParticipants = groups.reduce((acc, g) => acc + g.participants.length, 0)

    // Конфликты расписания: группы с одним курсом и одной датой начала
    const conflicts = []
    const byCourseDateStart = {}
    groups.forEach(g => {
        const key = `${g.courseId}__${g.startDate}`
        if (!byCourseDateStart[key]) byCourseDateStart[key] = []
        byCourseDateStart[key].push(g)
    })
    Object.values(byCourseDateStart).forEach(arr => {
        if (arr.length > 1) conflicts.push(...arr)
    })
    const conflictIds = new Set(conflicts.map(g => g.id))

    // Итого по всем спецификациям
    const totalRevenue = specifications.reduce((acc, sp) => {
        const { total } = calcSpecTotals(sp, groups, courses)
        return acc + total
    }, 0)

    const recentGroups = [...groups]
        .sort((a, b) => b.startDate > a.startDate ? -1 : 1)
        .slice(0, 5)

    return (
        <div className="page-enter">
            <PageHeader
                title="Дашборд"
                subtitle="Общая сводка по системе корпоративного обучения"
            />

            {/* KPI stats */}
            <div className="grid-4" style={{ marginBottom: 24 }}>
                {[
                    {
                        label: 'Учебных групп', value: groups.length,
                        sub: `${activeGroups.length} активных`,
                        icon: GraduationCap, color: '#4da6ff',
                        onClick: () => navigate('/groups'),
                    },
                    {
                        label: 'Курсов', value: courses.length,
                        sub: 'в каталоге',
                        icon: BookOpen, color: '#7c8ff5',
                        onClick: () => navigate('/courses'),
                    },
                    {
                        label: 'Сотрудников', value: employees.length,
                        sub: `${totalParticipants} участий`,
                        icon: Users, color: '#34d399',
                        onClick: () => navigate('/employees'),
                    },
                    {
                        label: 'Выручка (НДС)', value: `${fmt(totalRevenue)} ₽`,
                        sub: `${specifications.length} спецификаций`,
                        icon: FileText, color: '#fbbf24',
                        onClick: () => navigate('/specifications'),
                        small: true,
                    },
                ].map((s, i) => (
                    <div
                        key={i}
                        className="stat-card"
                        style={{ cursor: 'pointer' }}
                        onClick={s.onClick}
                    >
                        <div style={{
                            display: 'flex', alignItems: 'flex-start',
                            justifyContent: 'space-between', marginBottom: 12,
                        }}>
                            <div style={{
                                width: 36, height: 36, borderRadius: 10,
                                background: `${s.color}18`,
                                border: `1px solid ${s.color}30`,
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                            }}>
                                <s.icon size={16} color={s.color} />
                            </div>
                            <ChevronRight size={14} color="var(--text-tertiary)" />
                        </div>
                        <div className="stat-value" style={{ fontSize: s.small ? 20 : 28 }}>
                            {s.value}
                        </div>
                        <div className="stat-label">{s.label}</div>
                        <div style={{ fontSize: 11, color: 'var(--text-tertiary)', marginTop: 2 }}>
                            {s.sub}
                        </div>
                    </div>
                ))}
            </div>

            {/* Gantt Chart Placeholder */}
            <div style={{ marginBottom: 24 }}>
                <div className="glass-card" style={{ padding: 0, overflow: 'hidden' }}>
                    <div style={{
                        padding: '16px 20px',
                        borderBottom: '1px solid var(--border-subtle)',
                        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                            <Calendar size={18} color="var(--accent-blue)" />
                            <span style={{ fontSize: 14, fontWeight: 600, letterSpacing: '-0.02em' }}>
                                Диаграмма Ганта
                            </span>
                        </div>
                        <span style={{ fontSize: 11, color: 'var(--text-tertiary)', fontWeight: 500 }}>
                            {groups.length} групп
                        </span>
                    </div>

                    <div style={{
                        padding: '32px 20px',
                        display: 'flex', flexDirection: 'column', alignItems: 'center',
                        justifyContent: 'center', minHeight: '300px',
                        background: 'rgba(255, 255, 255, 0.02)',
                    }}>
                        <div style={{
                            padding: '16px',
                            background: 'rgba(77, 166, 255, 0.1)',
                            border: '1px solid rgba(77, 166, 255, 0.2)',
                            borderRadius: 'var(--radius-lg)',
                            textAlign: 'center',
                            maxWidth: '400px',
                        }}>
                            <div style={{
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                gap: 8, marginBottom: 8,
                            }}>
                                <AlertCircle size={18} color="var(--accent-blue)" />
                                <span style={{ fontSize: 13, fontWeight: 600 }}>
                                    Компонент в разработке
                                </span>
                            </div>
                            <p style={{
                                fontSize: 12, color: 'var(--text-secondary)', margin: 0,
                                lineHeight: '1.6',
                            }}>
                                Интерактивная диаграмма Ганта для отображения расписания курсов будет доступна в следующей версии.
                            </p>
                        </div>

                        <div style={{
                            marginTop: '20px',
                            display: 'grid',
                            gridTemplateColumns: 'repeat(3, 1fr)',
                            gap: '12px',
                            width: '100%',
                        }}>
                            {[
                                { label: 'Временная шкала', value: 'Q2-Q3 2026' },
                                { label: 'Видимо групп', value: groups.length },
                                { label: 'Курсов в плане', value: courses.length },
                            ].map((item, i) => (
                                <div key={i} style={{
                                    padding: '12px',
                                    background: 'rgba(255, 255, 255, 0.05)',
                                    border: '1px solid rgba(255, 255, 255, 0.08)',
                                    borderRadius: '8px',
                                    textAlign: 'center',
                                }}>
                                    <div style={{ fontSize: 11, color: 'var(--text-tertiary)', marginBottom: 4 }}>
                                        {item.label}
                                    </div>
                                    <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>
                                        {item.value}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 340px', gap: 20 }}>
                {/* Recent groups */}
                <div className="glass-card" style={{ padding: 0, overflow: 'hidden' }}>
                    <div style={{
                        padding: '16px 20px',
                        borderBottom: '1px solid var(--border-subtle)',
                        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                    }}>
            <span style={{ fontSize: 14, fontWeight: 600, letterSpacing: '-0.02em' }}>
              Учебные группы
            </span>
                        <button
                            className="btn btn-ghost btn-sm"
                            onClick={() => navigate('/groups')}
                            style={{ fontSize: 12 }}
                        >
                            Все группы <ChevronRight size={12} />
                        </button>
                    </div>
                    <table>
                        <thead>
                        <tr>
                            <th>Курс</th>
                            <th>Период</th>
                            <th>Участников</th>
                            <th>Прогресс</th>
                            <th>Статус</th>
                        </tr>
                        </thead>
                        <tbody>
                        {recentGroups.map(g => {
                            const course = courses.find(c => c.id === g.courseId)
                            const progress = calcGroupProgress(g)
                            const isConflict = conflictIds.has(g.id)
                            return (
                                <tr
                                    key={g.id}
                                    onClick={() => navigate(`/groups/${g.id}`)}
                                    style={{
                                        cursor: 'pointer',
                                        background: isConflict ? 'rgba(251,191,36,0.04)' : undefined,
                                    }}
                                >
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                            {isConflict && (
                                                <AlertTriangle size={12} color="var(--accent-amber)" />
                                            )}
                                            <span style={{ fontWeight: 500, fontSize: 13 }}>
                          {course?.name || '—'}
                        </span>
                                        </div>
                                    </td>
                                    <td style={{ color: 'var(--text-secondary)', fontSize: 12 }}>
                                        {g.startDate} — {g.endDate}
                                    </td>
                                    <td>
                                        <span style={{ fontSize: 13 }}>{g.participants.length}</span>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 8, minWidth: 80 }}>
                                            <div className="progress-bar" style={{ flex: 1 }}>
                                                <div className="progress-bar-fill" style={{ width: `${progress}%` }} />
                                            </div>
                                            <span style={{ fontSize: 11, color: 'var(--text-secondary)', width: 28 }}>
                          {progress}%
                        </span>
                                        </div>
                                    </td>
                                    <td><StatusBadge status={g.status} /></td>
                                </tr>
                            )
                        })}
                        {groups.length === 0 && (
                            <tr>
                                <td colSpan={5}>
                                    <div className="empty-state" style={{ padding: '32px 0' }}>
                                        <div className="empty-state-title">Нет групп обучения</div>
                                    </div>
                                </td>
                            </tr>
                        )}
                        </tbody>
                    </table>
                </div>

                {/* Right column */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                    {/* Conflicts */}
                    {conflicts.length > 0 && (
                        <div style={{
                            padding: '14px 16px',
                            background: 'rgba(251,191,36,0.06)',
                            border: '1px solid rgba(251,191,36,0.2)',
                            borderRadius: 'var(--radius-xl)',
                        }}>
                            <div style={{
                                display: 'flex', alignItems: 'center', gap: 8,
                                marginBottom: 10, fontSize: 13, fontWeight: 600,
                                color: 'var(--accent-amber)',
                            }}>
                                <AlertTriangle size={14} />
                                Конфликты расписания ({conflicts.length})
                            </div>
                            {[...new Set(conflicts.map(g => `${g.courseId}__${g.startDate}`))].map(key => {
                                const [courseId, date] = key.split('__')
                                const course = courses.find(c => c.id === courseId)
                                const grps = conflicts.filter(g => g.courseId === courseId && g.startDate === date)
                                return (
                                    <div key={key} style={{
                                        padding: '8px 10px',
                                        background: 'rgba(251,191,36,0.06)',
                                        borderRadius: 8,
                                        marginBottom: 6,
                                        fontSize: 12,
                                    }}>
                                        <div style={{ fontWeight: 500, marginBottom: 2 }}>
                                            {course?.name}
                                        </div>
                                        <div style={{ color: 'var(--text-tertiary)' }}>
                                            {date} · {grps.length} группы
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    )}

                    {/* Companies breakdown */}
                    <div className="glass-card" style={{ padding: 16 }}>
                        <div style={{
                            fontSize: 13, fontWeight: 600, letterSpacing: '-0.02em',
                            marginBottom: 12,
                        }}>
                            По компаниям
                        </div>
                        {companies.map(company => {
                            const empCount = employees.filter(e => e.companyId === company.id).length
                            const specCount = specifications.filter(s => s.companyId === company.id).length
                            return (
                                <div key={company.id} style={{
                                    display: 'flex', alignItems: 'center',
                                    justifyContent: 'space-between',
                                    padding: '8px 0',
                                    borderBottom: '1px solid var(--border-subtle)',
                                    fontSize: 12,
                                }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                        <div style={{
                                            width: 26, height: 26, borderRadius: 6,
                                            background: 'var(--glass-3)',
                                            border: '1px solid var(--border-default)',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            fontSize: 9, fontWeight: 700, color: 'var(--accent-blue)',
                                            letterSpacing: '0.02em',
                                        }}>
                                            {company.code}
                                        </div>
                                        <span style={{ fontWeight: 500 }}>{company.name}</span>
                                    </div>
                                    <div style={{ color: 'var(--text-tertiary)', fontSize: 11 }}>
                                        {empCount} сотр. · {specCount} спец.
                                    </div>
                                </div>
                            )
                        })}
                        {companies.length === 0 && (
                            <div style={{ fontSize: 12, color: 'var(--text-tertiary)' }}>
                                Нет компаний
                            </div>
                        )}
                    </div>

                    {/* Quick stats */}
                    <div className="glass-card" style={{ padding: 16 }}>
                        <div style={{
                            fontSize: 13, fontWeight: 600, letterSpacing: '-0.02em',
                            marginBottom: 12,
                        }}>
                            Статистика групп
                        </div>
                        {[
                            { label: 'Планируется', count: plannedGroups.length, color: 'var(--status-planned)' },
                            { label: 'В процессе', count: activeGroups.length, color: 'var(--status-active)' },
                            { label: 'Завершено', count: groups.filter(g => g.status === 'done').length, color: 'var(--text-tertiary)' },
                        ].map(s => (
                            <div key={s.label} style={{
                                display: 'flex', alignItems: 'center',
                                justifyContent: 'space-between',
                                padding: '6px 0',
                                fontSize: 12,
                            }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                    <div style={{
                                        width: 6, height: 6, borderRadius: '50%',
                                        background: s.color, flexShrink: 0,
                                    }} />
                                    <span style={{ color: 'var(--text-secondary)' }}>{s.label}</span>
                                </div>
                                <span style={{ fontWeight: 600, color: s.color }}>{s.count}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    )
}

